     1→/**
     2→ * Query Parser for md-tldr search
     3→ *
     4→ * Supports:
     5→ * - Boolean operators: AND, OR, NOT (case-insensitive)
     6→ * - Quoted phrases: "exact phrase"
     7→ * - Grouping: (term1 OR term2) AND term3
     8→ * - Precedence: NOT > AND > OR
     9→ */
    10→
    11→// ============================================================================
    12→// Types
    13→// ============================================================================
    14→
    15→export type QueryNode =
    16→  | { type: 'term'; value: string }
    17→  | { type: 'phrase'; value: string }
    18→  | { type: 'and'; left: QueryNode; right: QueryNode }
    19→  | { type: 'or'; left: QueryNode; right: QueryNode }
    20→  | { type: 'not'; operand: QueryNode }
    21→
    22→export interface ParsedQuery {
    23→  readonly ast: QueryNode
    24→  readonly terms: readonly string[]
    25→  readonly phrases: readonly string[]
    26→}
    27→
    28→// ============================================================================
    29→// Tokenizer
    30→// ============================================================================
    31→
    32→type TokenType = 'AND' | 'OR' | 'NOT' | 'LPAREN' | 'RPAREN' | 'PHRASE' | 'TERM'
    33→
    34→interface Token {
    35→  type: TokenType
    36→  value: string
    37→}
    38→
    39→/**
    40→ * Tokenize query string into tokens
    41→ */
    42→const tokenize = (query: string): Token[] => {
    43→  const tokens: Token[] = []
    44→  let i = 0
    45→
    46→  while (i < query.length) {
    47→    // Skip whitespace
    48→    if (/\s/.test(query[i]!)) {
    49→      i++
    50→      continue
    51→    }
    52→
    53→    // Quoted phrase
    54→    if (query[i] === '"') {
    55→      const start = i + 1
    56→      i++
    57→      while (i < query.length && query[i] !== '"') {
    58→        i++
    59→      }
    60→      const value = query.slice(start, i)
    61→      tokens.push({ type: 'PHRASE', value })
    62→      i++ // Skip closing quote
    63→      continue
    64→    }
    65→
    66→    // Parentheses
    67→    if (query[i] === '(') {
    68→      tokens.push({ type: 'LPAREN', value: '(' })
    69→      i++
    70→      continue
    71→    }
    72→    if (query[i] === ')') {
    73→      tokens.push({ type: 'RPAREN', value: ')' })
    74→      i++
    75→      continue
    76→    }
    77→
    78→    // Words (operators or terms)
    79→    const wordMatch = query.slice(i).match(/^[^\s()"]+/)
    80→    if (wordMatch) {
    81→      const word = wordMatch[0]
    82→      const upperWord = word.toUpperCase()
    83→
    84→      if (upperWord === 'AND') {
    85→        tokens.push({ type: 'AND', value: 'AND' })
    86→      } else if (upperWord === 'OR') {
    87→        tokens.push({ type: 'OR', value: 'OR' })
    88→      } else if (upperWord === 'NOT') {
    89→        tokens.push({ type: 'NOT', value: 'NOT' })
    90→      } else {
    91→        tokens.push({ type: 'TERM', value: word })
    92→      }
    93→      i += word.length
    94→      continue
    95→    }
    96→
    97→    // Unknown character, skip
    98→    i++
    99→  }
   100→
   101→  return tokens
   102→}
   103→
   104→// ============================================================================
   105→// Parser (Recursive Descent)
   106→// ============================================================================
   107→
   108→/**
   109→ * Parser for boolean query expressions.
   110→ * Grammar:
   111→ *   expr     -> andExpr (OR andExpr)*
   112→ *   andExpr  -> notExpr (AND notExpr)*
   113→ *   notExpr  -> NOT notExpr | primary
   114→ *   primary  -> TERM | PHRASE | LPAREN expr RPAREN
   115→ */
   116→class Parser {
   117→  private tokens: Token[]
   118→  private pos: number = 0
   119→  readonly terms: string[] = []
   120→  readonly phrases: string[] = []
   121→
   122→  constructor(tokens: Token[]) {
   123→    this.tokens = tokens
   124→  }
   125→
   126→  private current(): Token | undefined {
   127→    return this.tokens[this.pos]
   128→  }
   129→
   130→  private advance(): Token | undefined {
   131→    return this.tokens[this.pos++]
   132→  }
   133→
   134→  private match(type: TokenType): boolean {
   135→    if (this.current()?.type === type) {
   136→      this.advance()
   137→      return true
   138→    }
   139→    return false
   140→  }
   141→
   142→  parse(): QueryNode | null {
   143→    if (this.tokens.length === 0) {
   144→      return null
   145→    }
   146→    return this.parseExpr()
   147→  }
   148→
   149→  private parseExpr(): QueryNode {
   150→    let left = this.parseAndExpr()
   151→
   152→    while (this.match('OR')) {
   153→      const right = this.parseAndExpr()
   154→      left = { type: 'or', left, right }
   155→    }
   156→
   157→    return left
   158→  }
   159→
   160→  private parseAndExpr(): QueryNode {
   161→    let left = this.parseNotExpr()
   162→
   163→    // Handle implicit AND (terms without explicit AND between them)
